import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from 'react-router-dom';


import logoImage from './assets/favicon.jpg';
import './App.css';

// Importă componentele paginii (presupunând structura de foldere)
import Login from './components/Auth/Login';
import Register from './components/Auth/Register';
import ProfilePage from './components/Profile/ProfilePage';
import Home from './components/Home/Home';

// O componentă mică pentru Logout...
const LogoutButton: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
    // ... codul pentru LogoutButton ...
    const navigate = useNavigate();

    const handleClick = () => {
        onLogout();
        navigate('/login');
    };

    return (
        <button onClick={handleClick} className="nav-button logout-button">
            Logout
        </button>
    );
};


const App: React.FC = () => {
    const [currentUser, setCurrentUser] = useState<string | null>(
        localStorage.getItem('username')
    );

    const handleLogin = (username: string) => {
        setCurrentUser(username);
    };

    const handleLogout = () => {
        setCurrentUser(null);
        localStorage.removeItem('token');
        localStorage.removeItem('username');
        localStorage.removeItem('userId');
    };

    return (
        <Router>
            <div>
                {/* <VideoBackground /> A FOST ȘTERS DE AICI */}

                <nav className="nav-container">
                    {/* ... codul tău de navigare ... */}
                </nav>

                <div className="content-container">
                    <Routes>
                        <Route path="/login" element={<Login onLoginSuccess={handleLogin} />} />
                        <Route path="/register" element={<Register />} />
                        <Route path="/profile" element={<ProfilePage />} />
                        <Route path="/" element={<Home />} />
                    </Routes>
                </div>
            </div>
        </Router>
    );
};

export default App;
